<template>
  <div>
        <!-- 面包屑导航 -->
        <el-breadcrumb separator="/">
            <el-breadcrumb-item :to="{ path: '/' }">首页</el-breadcrumb-item>
            <el-breadcrumb-item><a href="/">商品管理</a></el-breadcrumb-item>
            <el-breadcrumb-item>商品分类</el-breadcrumb-item>
        </el-breadcrumb>

        <!-- 卡片试图 -->
        <el-card>
            <!-- 按钮 -->
             <el-row>
                 <el-col>
                     <el-button type="primary" style="margin-bottom:20px;" @click="showAddCate">添加分类</el-button>
                 </el-col>
             </el-row>
             <!-- 表格 -->
             <tree-table :data="cateList" :columns="columns" :show-index="true" index-text="#" border :expand-type="false" :selection-type="false">
                 <!-- 是否有效 -->
                 <template slot="isok" slot-scope="scope">
                     <i class="el-icon-success" v-if="scope.row.cat_deleted===false" style="color:lightgreen"></i>
                     <i class="el-icon-error" v-else style="color:red"></i>
                 </template>
                 <!-- 排序 -->
                 <template slot="order" slot-scope="scope">
                    <el-tag size="mini" v-if="scope.row.cat_level===0">一级</el-tag>
                    <el-tag size="mini" type="success" v-else-if="scope.row.cat_level===1">二级</el-tag>
                    <el-tag size="mini" type="warning" v-else>三级</el-tag>
                 </template>
                 <template slot="opt" slot-scope="scope">
                    <el-button type="primary" icon="el-icon-edit" size="mini">编辑</el-button>
                    <el-button type="danger" icon="el-icon-delete" size="mini">删除</el-button>
                 </template>
             </tree-table>

             <!-- 分页 -->
             <el-pagination
                @size-change="handleSizeChange"
                @current-change="handleCurrentChange"
                :current-page="queryInfo.pagenum"
                :page-sizes="[3,5,10,15]"
                :page-size="queryInfo.pagesize"
                layout="total, sizes, prev, pager, next, jumper"
                :total="total">
            </el-pagination>
            
        </el-card>

        <!-- 点击添加出现的对话框 -->
        <el-dialog
            title="提示"
            :visible.sync="addCateDialogVisible"
            width="30%">
            <el-form :model="addCateForm" :rules="addCateFormRules" ref="addCateFormRef" label-width="100px">
                <el-form-item label="分类名称" prop="cat_name">
                    <el-input v-model="addCateForm.cat_name"></el-input>
                </el-form-item>
                <el-form-item label="父级分类">
                    <!-- 级联选择器 options用来指定数据源-->
                    <el-cascader
                        expand-trigger="hover"
                        v-model="selectedKeys"
                        :options="ParentCateList"
                        :props="cascaderProps"
                        @change="parentCateChange">
                    </el-cascader>
                </el-form-item>
            </el-form>
            <span slot="footer" class="dialog-footer">
                <el-button @click="addCateDialogVisible = false">取 消</el-button>
                <el-button type="primary" @click="addCateDialogVisible = false">确 定</el-button>
            </span>
        </el-dialog>

       
        
  </div>
</template>

<script>
export default {
  name: '',
  data() { 
    return {
        cateList:[],   //商品分类列表
        queryInfo:{   //查询条件
            type:3,
            pagenum:1,
            pagesize:5
        },
        total:0,   //总数据条数
        columns:[   //table指定列定义
           {
               label:'分类名称',
               prop:'cat_name'
           },
           {
               label:'是否有效',
               type:'template',
               template:'isok'
           },
           {
               label:'排序',
               type:'template',
               template:'order'
           },
           {
               label:'排操作序',
               type:'template',
               template:'opt'
           }
        ],  
        addCateDialogVisible:false,
        addCateForm:{   //添加分类的数据对象 
            cat_name:'',
            cat_pid:0,   //分类的id
            cat_level:0,   //分类的等级
        },  
        addCateFormRules:{
            cat_name:[  //将要添加的分类名称
                {
                   required:true,
                   message:'请输入分类名称',
                   trigger:'blur'
               }
            ],   
        },
        ParentCateList:[],   //父级分类的列表
        cascaderProps:{
            value:'cat_id',
            label:'cat_name',
            children:'children'
        },   //指定级联选择器的具体配置对象
        selectedKeys:[],//选中的父级分类的id数组
    }
  },
  props: {

  },
  components:{
  },
  mounted() {
    this.getCateList()

  },
  methods:{
    async getCateList(){
        const { data:res } = await this.$axios.get('categories',{ params:this.queryInfo })
        console.log(res)
        if(res.meta.status!==200){
            return this.$message.error('获取商品分类失败')
        }
        this.cateList=res.data.result
        // 总数据条数赋值
        this.total=res.data.total
    },
    handleSizeChange(newSize){
        this.queryInfo.pagesize=newSize
        this.getCateList()
    },
    handleCurrentChange(newPage){
        this.queryInfo.pagenum=newPage
        this.getCateList()
    },
    // 点击添加分类
    showAddCate(){
        this.getParentCateList()
        this.addCateDialogVisible=true
    },
    // 获取父级分类的数据列表
    async getParentCateList(){
        const { data:res } = await this.$axios.get('categories',{params:{type:2}})
        if(res.meta.status!==200){
            return this.$message.error('获取父级分类列表失败')
        }
        this.ParentCateList=res.data
    },
    // 选择项发生变化触发
    parentCateChange(){
        console.log(this.selectedKeys)
    }

  },
 }
</script>

<style scoped>
.el-card{
    margin-top:15px;
}
.el-pagination{
    margin-top:15px;
}
.el-cascader{
    width:100%;
}
.el-cascader-menu__list{
    height:200px !important
}
</style>